import json
import pickle

def lambda_handler(event, context):
    # Deserialize the incoming JSON payload
    try:
        event_data = json.loads(event['body'])
    except Exception as e:
        return {
            'statusCode': 400,
            'body': json.dumps({'error': 'Invalid JSON payload'})
        }
    
    # Process the event data (example: print or further processing)
    processed_data = process_event(event_data)
    
    # Serialize the processed data using pickle
    try:
        serialized_data = pickle.dumps(processed_data)
    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps({'error': 'Failed to serialize data'})
        }
    
    return {
        'statusCode': 200,
        'headers': {
            'Content-Type': 'application/octet-stream'
        },
        'body': serialized_data
    }

def process_event(data):
    # Example processing logic (modify as needed)
    for action in data.get('actions', []):
        print(f"Processing action: {action}")
    return {"status": "processed", "data": data}